import type { ReactNode } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Activity, ExternalLink } from 'lucide-react';
import { cn } from '@/shadcn/lib/utils';
import {
  HoverCard,
  HoverCardContent,
  HoverCardTrigger,
} from '@/shadcn/components/ui/hover-card';
import { Badge } from '@/shadcn/components/ui/badge';
import { aboutService, type HealthInfo } from '@/api/aboutService';

function formatDateTime(iso: string): string {
  return new Date(iso).toLocaleString('en-US', {
    month: 'short',
    day: '2-digit',
    year: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
    hour12: true,
  });
}

function healthDotClass(status: HealthInfo['status'] | undefined, isError: boolean): string {
  if (isError) return 'bg-rose-500';
  if (!status) return 'bg-muted-foreground/40';
  if (status === 'Healthy') return 'bg-emerald-500';
  if (status === 'Degraded') return 'bg-amber-500';
  return 'bg-rose-500';
}

function healthBadgeClass(status: HealthInfo['status']): string {
  if (status === 'Healthy') return 'border-emerald-500/30 bg-emerald-500/10 text-emerald-600 dark:text-emerald-400';
  if (status === 'Degraded') return 'border-amber-500/30 bg-amber-500/10 text-amber-600 dark:text-amber-400';
  return 'border-rose-500/30 bg-rose-500/10 text-rose-600 dark:text-rose-400';
}

function envBadgeClass(env: string): string {
  if (env === 'Production') return 'border-primary/30 bg-primary/10 text-primary';
  return 'border-border bg-muted text-muted-foreground';
}

export function ApiStatus({ className }: { className?: string }) {
  const { data: about } = useQuery({
    queryKey: ['api-about'],
    queryFn: aboutService.getAbout,
    staleTime: 5 * 60 * 1000,
    retry: 1,
  });

  const { data: health, isError: healthError } = useQuery({
    queryKey: ['api-health'],
    queryFn: aboutService.getHealth,
    refetchInterval: 180_000,
    retry: 1,
  });

  const dotClass = healthDotClass(health?.status, healthError);
  const isPulsing = !healthError && (health?.status === 'Healthy' || (!health && !healthError));

  const hasComponents = health?.components && Object.keys(health.components).length > 0;

  return (
    <HoverCard openDelay={200} closeDelay={100}>
      <HoverCardTrigger asChild>
        <button
          title="API Status"
          className={cn(
            'relative flex h-9 w-9 items-center justify-center rounded-xl',
            'bg-primary/10 text-primary transition-colors hover:bg-primary/20',
            className,
          )}
        >
          <Activity className="h-4 w-4" strokeWidth={2.5} />
          <span
            className={cn(
              'absolute right-1.5 top-1.5 h-2 w-2 rounded-full',
              dotClass,
              isPulsing && 'animate-pulse',
            )}
          />
          <span className="sr-only">API Status</span>
        </button>
      </HoverCardTrigger>

      <HoverCardContent
        align="end"
        sideOffset={8}
        className="w-96 p-0 overflow-hidden"
      >
        {/* Header */}
        <div className="flex flex-wrap items-center gap-x-3 gap-y-1.5 border-b border-border px-4 py-3">
          <div className="flex items-center gap-2 mr-auto">
            <Activity className="h-3.5 w-3.5 shrink-0 text-muted-foreground" />
            <span className="text-xs font-bold uppercase tracking-widest text-muted-foreground whitespace-nowrap">
              API Status
            </span>
          </div>
          <div className="flex items-center gap-2 flex-wrap">
            {about?.environment && (
              <Badge
                variant="outline"
                className={cn('h-5 px-2 text-[10px] font-bold uppercase tracking-wider rounded-full whitespace-nowrap', envBadgeClass(about.environment))}
              >
                {about.environment}
              </Badge>
            )}
            {healthError ? (
              <Badge
                variant="outline"
                className="h-5 px-2 text-[10px] font-bold uppercase tracking-wider rounded-full whitespace-nowrap border-rose-500/30 bg-rose-500/10 text-rose-600 dark:text-rose-400"
              >
                Unreachable
              </Badge>
            ) : health?.status && (
              <Badge
                variant="outline"
                className={cn('h-5 px-2 text-[10px] font-bold uppercase tracking-wider rounded-full whitespace-nowrap', healthBadgeClass(health.status))}
              >
                {health.status}
              </Badge>
            )}
          </div>
        </div>

        {/* Details */}
        <div className="space-y-1 px-4 py-3">
          {about ? (
            <>
              <Row label="Version" value={about.version.split('+')[0]} />
              <Row
                label="Commit"
                value={
                  <a
                    href={about.commitUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-flex items-center gap-1 font-mono text-xs text-primary hover:underline"
                  >
                    {about.commit}
                    <ExternalLink className="h-2.5 w-2.5" />
                  </a>
                }
              />
              <Row label="Built" value={formatDateTime(about.builtAt)} />
              <Row label="Running Since" value={health?.appRunningSince ?? about.appRunningSince} />
            </>
          ) : (
            <SkeletonRows count={4} />
          )}

          <div className="my-2 h-px bg-border" />

          {health ? (
            <Row label="Started" value={formatDateTime(health.appStartedAt)} />
          ) : healthError ? (
            <p className="text-xs text-rose-500">Could not reach the API. Check your connection or server status.</p>
          ) : (
            <SkeletonRows count={1} />
          )}

          {hasComponents && (
            <>
              <div className="my-2 h-px bg-border" />
              {Object.entries(health!.components).map(([key, val]) => (
                <Row key={key} label={key} value={String(val)} />
              ))}
            </>
          )}
        </div>
      </HoverCardContent>
    </HoverCard>
  );
}

function Row({ label, value }: { label: string; value: ReactNode }) {
  return (
    <div className="flex items-start justify-between gap-4 py-0.5">
      <span className="shrink-0 text-[11px] font-bold uppercase tracking-wider text-muted-foreground/70">
        {label}
      </span>
      <span className="text-right text-xs text-foreground/80">
        {value}
      </span>
    </div>
  );
}

function SkeletonRows({ count }: { count: number }) {
  return (
    <>
      {Array.from({ length: count }).map((_, i) => (
        <div key={i} className="flex items-center justify-between py-0.5">
          <div className="h-2.5 w-14 animate-pulse rounded bg-muted" />
          <div className="h-2.5 w-28 animate-pulse rounded bg-muted" />
        </div>
      ))}
    </>
  );
}
